/* 进入 STOP2 前的完整准备序列 */
void system_enter_stop2(void)
{
    /* Step 1: 关闭所有不需要的时钟 */
    __HAL_RCC_ADC_CLK_DISABLE();
    __HAL_RCC_I2C1_CLK_DISABLE();
    __HAL_RCC_SPI2_CLK_DISABLE();

    /* Step 2: 确认 ADC 电源已断开 */
    while (ADC1->CR & ADC_CR_ADEN) {
        ADC1->CR &= ~ADC_CR_ADEN;
    }

    /* Step 3: 配置 GPIO 为模拟输入减少漏电 */
    GPIOB->MODER = 0x00000000U;

    /* Step 4: 清除旧唤醒标志，防止误唤醒 */
    __HAL_PWR_CLEAR_WUF_FLAG();

    /* Step 5: 设置 PWR_CR1 选择 STOP2 模式 */
    __HAL_PWR_VOLTAGESCALING_CONFIG(PWR_REGULATOR_VOLTAGE_SCALE3);

    /* Step 6: 等待 VOS 位稳定 */
    while (__HAL_PWR_GET_FLAG(PWR_FLAG_VOSRDY) == 0);

    /* Step 7: 进入 STOP2 —— Halted 指令触发 */
    HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON,
                          PWR_STOPENTRY_WFI);
}
