/* 唤醒后恢复序列（从 main 入口调用） */
void system_post_wakeup(void)
{
    /* Step 1: 重新配置系统时钟（STOP 后默认 HSI） */
    SystemClock_Config();

    /* Step 2: 恢复外设初始化 */
    HAL_ADCEx_Calibration_Start(&hadc1);
    I2C1_Init();

    /* Step 3: 清除唤醒标志防止重复进入 */
    __HAL_PWR_CLEAR_WUF_FLAG();
}

