/* === 改进前：散落在 main.c 中的睡眠逻辑 === */

void check_sleep_condition(void)
{
    if (no_activity > 300) {
        __HAL_RCC_ADC_CLK_DISABLE();
        __HAL_PWR_CLEAR_WUF_FLAG();
        HAL_PWR_EnterSTOPMode(
            PWR_LOWPOWERREGULATOR_ON,
            PWR_STOPENTRY_WFI);
        /* 唤醒后恢复 */
        SystemClock_Config();
        I2C1_Init();
        __HAL_PWR_CLEAR_WUF_FLAG();
    } else if (battery_low && !charging) {
        __HAL_RCC_GPIOB_CLK_DISABLE();
        __HAL_RCC_ADC_CLK_DISABLE();
        __HAL_PWR_CLEAR_WUF_FLAG();
        /* 进 STANDBY */
        PWR->CR |= PWR_CR_PDDS;
        NVIC->SysTick_CTRL = 0;
        HAL_PWR_EnterSTANDBYMode();
    }
}

/* === 改进后：策略模式封装 === */

typedef struct {
    const char *name;
    uint8_t max_depth;  /* 0=SLEEP, 1=STOP2, 2=STANDBY */
    void (*pre_enter)(void);
    void (*post_wakeup)(void);
} power_strategy_t;

static power_strategy_t strategies[4];
static uint8_t strategy_count = 0;

uint8_t power_register_strategy(
    power_strategy_t *s)
{
    if (strategy_count >= 4) return 1;
    strategies[strategy_count++] = *s;
    return 0;
}

void power_manager_select_and_enter(
    uint8_t depth)
{
    /* 找到最深可用且不超 depth 的策略 */
    for (int i = strategy_count - 1; i >= 0; i--) {
        if (strategies[i].max_depth <= depth) {
            __HAL_PWR_CLEAR_WUF_FLAG();
            if (strategies[i].pre_enter)
                strategies[i].pre_enter();
            /* 核心函数统一处理 HAL 调用 */
            _power_enter_mode(strategies[i].max_depth);
            if (strategies[i].post_wakeup)
                strategies[i].post_wakeup();
            return;
        }
    }
}

/* 注册具体场景策略 */
static void btn_timeout_pre(void)
{
    __HAL_RCC_ADC_CLK_DISABLE();
}
static void btn_timeout_post(void)
{
    SystemClock_Config();
    I2C1_Init();
}

power_strategy_t btn_strategy = {
    .name = "btn_timeout",
    .max_depth = 1,  /* STOP2 */
    .pre_enter = btn_timeout_pre,
    .post_wakeup = btn_timeout_post
};
```

改了什么：把散落的 HAL_PWR_EnterSTOPMode 和时钟门控调用抽入策略回调，核心函数 power_manager_select_and_enter 只做一件事——选最深安全模式并执行对应策略。为什么这样改：避免每个场景重复写相同的清除标志和时钟恢复代码，减少遗漏风险。代价：增加了策略注册表和间接调用开销（约 2us），以及 40 行框架代码，但对于超过 3 个睡眠场景的项目来说已经回本。
